#!/usr/bin/env bash
# Pool management for the FULL Lium fleet (replaces pool.sh's hardcoded BOXES).
#
# Reads bench/hosts.env (auto-generated by bench/lium_fleet.py write-hosts).
#
# Subcommands:
#   sync                     rsync source + .env + setup_fleet.sh to every box
#   status                   per-box: alive workers, alive orch, log files
#   bootstrap TASK RUN_ID R  bootstrap on master
#   start TASK RUN_ID NUB DEVICE       sync-round mode, pin to UB
#   start-pipe TASK RUN_ID NSTAGES DEVICE   streaming mode, pin to STAGE
#   start-validator RUN_ID DEVICE      start one replay validator on master
#   tail-validator                    tail validator log on master
#   ledger RUN_ID                     print receipt/verdict CU summary
#   stop                     kill all bench.dist procs everywhere
#   wipe RUN_ID              wipe S3 prefix
#   tail RUN_ID ROUNDS

set -euo pipefail

SSH_OPTS=(-o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o LogLevel=ERROR)
SSH() { ssh "${SSH_OPTS[@]}" "$@"; }
SCP() { scp "${SSH_OPTS[@]}" "$@"; }

HOSTS_ENV="${HOSTS_ENV:-bench/hosts.env}"
MASTER_TAG="${MASTER_TAG:-A}"

_load_boxes() {
  BOXES=()
  while IFS= read -r line; do
    [[ "$line" =~ ^# ]] && continue
    [[ -z "$line" ]] && continue
    BOXES+=("$line")
  done < "$HOSTS_ENV"
}

_for_each_box() {
  local fn=$1
  for spec in "${BOXES[@]}"; do
    read -r tag user host port nwork gpuclass price <<< "$spec"
    "$fn" "$tag" "$user" "$host" "$port" "$nwork" "$gpuclass" "$price"
  done
}

_master() {
  for spec in "${BOXES[@]}"; do
    read -r tag user host port nwork gpuclass price <<< "$spec"
    if [ "$tag" = "$MASTER_TAG" ]; then
      echo "$user $host $port"
      return
    fi
  done
  read -r tag user host port nwork gpuclass price <<< "${BOXES[0]}"
  echo "$user $host $port"
}

# -------- sync ---------------------------------------------------------------

_sync_one() {
  local tag=$1 user=$2 host=$3 port=$4 nwork=$5 gpuclass=$6
  echo "[sync $tag ${gpuclass}x${nwork}] -> $user@$host:$port"
  # Step 1: ensure rsync is installed remotely (some daturaai boxes lack it).
  SSH -p "$port" "$user@$host" "command -v rsync >/dev/null || (apt-get update -qq && apt-get install -y -qq rsync)" >/dev/null 2>&1 || true
  SSH -p "$port" "$user@$host" "mkdir -p /root/Teuton" >/dev/null 2>&1 || true
  # Step 2: rsync source.
  rsync -az --delete \
    --exclude '__pycache__' --exclude '.venv' --exclude '*.egg-info' \
    --exclude '.pytest_cache' \
    -e "ssh ${SSH_OPTS[*]} -p $port" \
    /Users/const/Teuton/Teuton/ "$user@$host:/root/Teuton/" >/dev/null 2>&1 || { echo "  ! rsync failed for $tag, falling back to scp"; SCP -P "$port" -r /Users/const/Teuton/Teuton/teuton /Users/const/Teuton/Teuton/bench /Users/const/Teuton/Teuton/pyproject.toml "$user@$host:/root/Teuton/" >/dev/null 2>&1; }
  # Step 3: copy .env.
  SCP -P "$port" /Users/const/Teuton/.env "$user@$host:/root/.env" >/dev/null 2>&1 || echo "  ! .env copy failed"
  # Step 4: run setup + install package.
  SSH -p "$port" "$user@$host" "bash /root/Teuton/bench/setup_fleet.sh 2>&1 | tail -5 && cd /root/Teuton && pip install --quiet --break-system-packages -e . 2>&1 | tail -1 || pip install --quiet -e . 2>&1 | tail -1" 2>&1 | tail -3
}

cmd_sync() { _load_boxes; _for_each_box _sync_one; echo "[sync] all ${#BOXES[@]} boxes synced"; }

# -------- status -------------------------------------------------------------

_status_one() {
  local tag=$1 user=$2 host=$3 port=$4 nwork=$5 gpuclass=$6
  out=$(SSH -p "$port" "$user@$host" \
    "ps aux | awk '/bench\\.dist worker/ && !/awk/' | wc -l; \
     ps aux | awk '/bench\\.dist (orchestrator|streaming-orchestrator)/ && !/awk/' | wc -l; \
     ps aux | awk '/bench\\.dist validator/ && !/awk/' | wc -l; \
     ls /tmp/teuton_logs/${tag}-w*.log 2>/dev/null | wc -l" 2>&1 || echo "0\n0\n0\n0")
  awk -v tag="$tag" -v expect="$nwork" -v gpu="$gpuclass" \
    'BEGIN{nw=0;no=0;nv=0;nl=0} NR==1{nw=$1} NR==2{no=$1} NR==3{nv=$1} NR==4{nl=$1} \
     END{printf "%-3s %-10s expect=%d alive_workers=%d alive_orch=%d alive_validator=%d log_files=%d\n", \
                 tag, gpu, expect, nw, no, nv, nl}' <<< "$out"
}

cmd_status() { _load_boxes; _for_each_box _status_one; }

# -------- bootstrap / start (sync-round mode) --------------------------------

cmd_bootstrap() {
  local task=$1 run=$2 rounds=$3
  _load_boxes
  read -r u h p <<< "$(_master)"
  SSH -p "$p" "$u@$h" \
    "cd /root/Teuton && python3 -m bench.dist bootstrap --task $task --run-id $run --max-rounds $rounds"
}

# Start workers on a single box (used by both sync-round and streaming).
# args: tag user host port nwork gpuclass run mode_arg device base_idx mode
_start_workers_one() {
  local tag=$1 user=$2 host=$3 port=$4 nwork=$5 gpuclass=$6
  local run=$7 nub_or_nstages=$8 device=$9 base_idx=${10} mode=${11}
  local wpoll="${WORKER_POLL_SEC:-0.1}"
  local hb="${WORKER_HEARTBEAT_SEC:-1.0}"
  local fault_mode=""
  local fault_rate="${WORKER_FAULT_RATE:-1.0}"
  if [[ ",${ADVERSARY_TAGS:-}," == *",$tag,"* ]]; then
    fault_mode="${WORKER_FAULT_MODE:-wrong_output}"
  fi

  SSH -p "$port" "$user@$host" "cat > /root/start_local.sh" <<'EOF'
#!/usr/bin/env bash
set -e
TAG=$1; RUN=$2; NUB=$3; DEVICE=$4; GPUCLASS=$5; BASE_IDX=$6; N=$7; MODE=$8; WPOLL=$9; HB=${10}; FAULT_MODE=${11}; FAULT_RATE=${12}
mkdir -p /tmp/teuton_logs
rm -f /tmp/teuton_logs/${TAG}-w*.log
for i in $(seq 0 $((N-1))); do
    GLOBAL_IDX=$((BASE_IDX + i))
    SLOT=$((GLOBAL_IDX % NUB))
    WID="${TAG}-w${i}"
    LOG="/tmp/teuton_logs/${WID}.log"
    if [ "$DEVICE" = "cuda" ]; then
        DEV_ARG="cuda:${i}"
    else
        DEV_ARG="cpu"
    fi
    if [ "$MODE" = "pipe" ]; then
        PIN_ARG="--pipe-stage $SLOT"
    else
        PIN_ARG="--resident-ub $SLOT"
    fi
    FAULT_ARGS=""
    if [ -n "$FAULT_MODE" ] && [ "$FAULT_MODE" != "none" ]; then
        FAULT_ARGS="--fault-mode $FAULT_MODE --fault-rate $FAULT_RATE"
    fi
    setsid nohup python3 -u -m bench.dist worker \
        --run-id "$RUN" \
        --worker-id "$WID" \
        $PIN_ARG \
        --gpu-class "$GPUCLASS" \
        --device "$DEV_ARG" \
        --poll-interval "$WPOLL" \
        --heartbeat-interval "$HB" \
        --max-idle-iters 10000 \
        $FAULT_ARGS \
        > "$LOG" 2>&1 < /dev/null &
done
sleep 1
echo "$TAG: $(pgrep -fa 'bench.dist worker' | wc -l) workers (base_idx=$BASE_IDX, n=$NUB, dev=$DEVICE, mode=$MODE, poll=$WPOLL, fault=${FAULT_MODE:-none})"
EOF
  SSH -p "$port" "$user@$host" \
    "cd /root/Teuton && bash /root/start_local.sh $tag $run $nub_or_nstages $device $gpuclass $base_idx $nwork $mode $wpoll $hb '$fault_mode' '$fault_rate'"
}

_start_orch() {
  local task=$1 run=$2 mode=$3
  local grace="${ORCH_GRACE_SEC:-90}"
  local poll="${ORCH_POLL_SEC:-0.2}"
  read -r u h p <<< "$(_master)"
  echo "[orch] starting on master ($MASTER_TAG = $u@$h:$p) mode=$mode grace=${grace}s poll=${poll}s"
  if [ "$mode" = "pipe" ]; then
    SUBCMD="streaming-orchestrator"
  else
    SUBCMD="orchestrator"
  fi
  SSH -p "$p" "$u@$h" "cat > /root/start_orch.sh" <<EOF
#!/usr/bin/env bash
set -e
TASK=\$1; RUN=\$2; GRACE=\$3; POLL=\$4
cd /root/Teuton
rm -f /tmp/teuton-orch.log
setsid bash -c "python3 -u -m bench.dist $SUBCMD --task \$TASK --run-id \$RUN --poll-interval \$POLL --startup-grace-sec \$GRACE >/tmp/teuton-orch.log 2>&1 </dev/null" >/dev/null 2>&1 </dev/null &
disown \$! 2>/dev/null || true
sleep 1
pgrep -fa "bench.dist" | head -2
EOF
  SSH -p "$p" "$u@$h" "bash /root/start_orch.sh $task $run $grace $poll"
}

cmd_start() {
  local task=$1 run=$2 nub=$3 device=$4
  _load_boxes
  echo "[start sync-round] task=$task run=$run nub=$nub device=$device"
  _start_orch "$task" "$run" "round"
  local base_idx=0
  for spec in "${BOXES[@]}"; do
    read -r tag user host port nwork gpuclass price <<< "$spec"
    _start_workers_one "$tag" "$user" "$host" "$port" "$nwork" "$gpuclass" \
      "$run" "$nub" "$device" "$base_idx" "round"
    base_idx=$((base_idx + nwork))
  done
  echo "[start] launched $base_idx workers across ${#BOXES[@]} boxes"
}

cmd_start_pipe() {
  local task=$1 run=$2 nstages=$3 device=$4
  _load_boxes
  echo "[start-pipe streaming] task=$task run=$run nstages=$nstages device=$device"
  _start_orch "$task" "$run" "pipe"
  local base_idx=0
  for spec in "${BOXES[@]}"; do
    read -r tag user host port nwork gpuclass price <<< "$spec"
    _start_workers_one "$tag" "$user" "$host" "$port" "$nwork" "$gpuclass" \
      "$run" "$nstages" "$device" "$base_idx" "pipe"
    base_idx=$((base_idx + nwork))
  done
  echo "[start-pipe] launched $base_idx workers across ${#BOXES[@]} boxes"
}

cmd_tail() {
  local run=$1 rounds=$2
  _load_boxes
  read -r u h p <<< "$(_master)"
  SSH -p "$p" "$u@$h" \
    "cd /root/Teuton && python3 -m bench.dist tail --run-id $run --max-rounds $rounds --poll-interval 2.0 --timeout-sec 3600.0"
}

cmd_start_validator() {
  local run=$1 device=${2:-cuda}
  _load_boxes
  read -r u h p <<< "$(_master)"
  local vid="${VALIDATOR_ID:-validator-${MASTER_TAG}}"
  local sample="${VALIDATOR_SAMPLE_RATE:-1.0}"
  local poll="${VALIDATOR_POLL_SEC:-2.0}"
  local max_jobs="${VALIDATOR_MAX_JOBS:-}"
  local timeout="${VALIDATOR_TIMEOUT_SEC:-}"
  local extra=""
  [ -n "$max_jobs" ] && extra="$extra --max-jobs $max_jobs"
  [ -n "$timeout" ] && extra="$extra --timeout-sec $timeout"
  SSH -p "$p" "$u@$h" "cat > /root/start_validator.sh" <<EOF
#!/usr/bin/env bash
set -e
RUN=\$1; VID=\$2; DEVICE=\$3; SAMPLE=\$4; POLL=\$5
cd /root/Teuton
rm -f /tmp/teuton-validator.log
setsid bash -c "python3 -u -m bench.dist validator --run-id \$RUN --validator-id \$VID --device \$DEVICE --sample-rate \$SAMPLE --poll-interval \$POLL $extra >/tmp/teuton-validator.log 2>&1 </dev/null" >/dev/null 2>&1 </dev/null &
disown \$! 2>/dev/null || true
sleep 1
pgrep -fa "bench.dist validator" || true
EOF
  SSH -p "$p" "$u@$h" "bash /root/start_validator.sh $run $vid $device $sample $poll"
}

cmd_tail_validator() {
  _load_boxes
  read -r u h p <<< "$(_master)"
  SSH -p "$p" "$u@$h" "tail -f /tmp/teuton-validator.log"
}

cmd_ledger() {
  local run=$1
  _load_boxes
  read -r u h p <<< "$(_master)"
  SSH -p "$p" "$u@$h" \
    "cd /root/Teuton && python3 -m bench.dist ledger --run-id $run"
}

_stop_one() {
  local tag=$1 user=$2 host=$3 port=$4
  SSH -p "$port" "$user@$host" \
    "ps aux | awk '/bench\\.dist (worker|orchestrator|streaming|validator)/ && !/awk/ {print \$2}' | xargs -r kill -9 2>/dev/null; \
     sleep 1; \
     echo \"$tag: alive=\$(ps aux | awk '/bench\\.dist (worker|orchestrator|streaming|validator)/ && !/awk/' | wc -l)\""
}

cmd_stop() { _load_boxes; _for_each_box _stop_one; }

cmd_wipe() {
  local run=$1
  _load_boxes
  read -r u h p <<< "$(_master)"
  SSH -p "$p" "$u@$h" \
    "cd /root/Teuton && python3 -m bench.dist wipe --run-id $run"
}

case "${1:-}" in
  sync)        cmd_sync ;;
  status)      cmd_status ;;
  bootstrap)   shift; cmd_bootstrap "$@" ;;
  start)       shift; cmd_start "$@" ;;
  start-pipe)  shift; cmd_start_pipe "$@" ;;
  start-validator) shift; cmd_start_validator "$@" ;;
  tail-validator) cmd_tail_validator ;;
  ledger)      shift; cmd_ledger "$@" ;;
  tail)        shift; cmd_tail "$@" ;;
  stop)        cmd_stop ;;
  wipe)        shift; cmd_wipe "$@" ;;
  *) cat <<USAGE
Usage:
  bench/fleet_pool.sh sync
  bench/fleet_pool.sh status
  bench/fleet_pool.sh bootstrap TASK RUN_ID ROUNDS
  bench/fleet_pool.sh start TASK RUN_ID NUB DEVICE        # sync-round mode
  bench/fleet_pool.sh start-pipe TASK RUN_ID NSTAGES DEVICE  # streaming mode
  bench/fleet_pool.sh start-validator RUN_ID [DEVICE]
  bench/fleet_pool.sh tail-validator
  bench/fleet_pool.sh ledger RUN_ID
  bench/fleet_pool.sh tail RUN_ID ROUNDS
  bench/fleet_pool.sh stop
  bench/fleet_pool.sh wipe RUN_ID
USAGE
  exit 1 ;;
esac
